var maxNumberOfFamilies = function(n, reservedSeats) {
    const rows = new Map();
    for (const [r, s] of reservedSeats) {
        if (s >= 2 && s <= 9) {
            rows.set(r, (rows.get(r) || 0) | (1 << (s - 2)));
        }
    }
    let total = 2 * (n - rows.size);
    const LEFT  = 0b00001111;
    const MID   = 0b00111100;
    const RIGHT = 0b11110000;
    for (const mask of rows.values()) {
        if (!(mask & LEFT) && !(mask & RIGHT)) {
            total += 2;
        } else if (!(mask & LEFT) || !(mask & MID) || !(mask & RIGHT)) {
            total += 1;
        }
    }
    return total;
};
